const resp = $('Recoger alertas (GET /alerts)').first().json;
const items = Array.isArray(resp) ? resp : (resp.items || []);

const TIPOLOGIA = { loyal: 'leal', promiscuous: 'promiscuo', at_risk: 'en riesgo de fuga', marginal: 'marginal' };
const CHANNEL_LABEL = { rep: 'Delegados comerciales', telesales: 'Televenta', marketing: 'Marketing', sin_canal: 'Sin canal asignado' };
const fmtInt = (n) => Math.round(Number(n) || 0).toLocaleString('de-DE');
const esc = (s) => String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const byChannel = {};
for (const a of items) { const ch = a.canal_recomendado || 'sin_canal'; (byChannel[ch] = byChannel[ch] || []).push(a); }

const out = [];
for (const [ch, list] of Object.entries(byChannel)) {
  const top = list.slice(0, 10);
  const rows = top.map(a => '<tr>' +
    '<td style="border:1px solid #ccc;padding:6px;">' + esc(a.id) + '</td>' +
    '<td style="border:1px solid #ccc;padding:6px;">' + esc(a.client_id) + '</td>' +
    '<td style="border:1px solid #ccc;padding:6px;">' + esc(a.provincia || a.province) + '</td>' +
    '<td style="border:1px solid #ccc;padding:6px;">' + esc(a.subfamilia) + '</td>' +
    '<td style="border:1px solid #ccc;padding:6px;">' + esc(TIPOLOGIA[a.tipologia_cliente] || a.tipologia_cliente) + '</td>' +
    '<td style="border:1px solid #ccc;padding:6px;">' + esc(a.motivo) + '</td>' +
    '<td style="border:1px solid #ccc;padding:6px;text-align:right;">' + esc(a.urgencia_dias) + '</td>' +
    '<td style="border:1px solid #ccc;padding:6px;text-align:right;">' + fmtInt(a.impacto_estimado) + ' &euro;</td>' +
    '<td style="border:1px solid #ccc;padding:6px;text-align:right;">' + fmtInt(a.prioridad_score) + '</td>' +
    '</tr>').join('');
  const totalImpact = list.reduce((s, a) => s + (Number(a.impacto_estimado) || 0), 0);
  const html = '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;color:#222;">' +
    '<h2 style="color:#1a4d8f;margin-bottom:4px;">Pulse &middot; Alertas prioritarias &mdash; ' + (CHANNEL_LABEL[ch] || ch) + '</h2>' +
    '<p>' + list.length + ' alerta(s) activa(s) para tu canal. Pipeline estimado del canal: <strong>' + fmtInt(totalImpact) + ' &euro;</strong>. Mostrando las ' + top.length + ' de mayor prioridad:</p>' +
    '<table style="border-collapse:collapse;width:100%;font-size:13px;"><thead><tr style="background:#1a4d8f;color:#fff;">' +
    '<th style="border:1px solid #ccc;padding:6px;">ID alerta</th><th style="border:1px solid #ccc;padding:6px;">Cliente</th><th style="border:1px solid #ccc;padding:6px;">Provincia</th><th style="border:1px solid #ccc;padding:6px;">Subfamilia</th><th style="border:1px solid #ccc;padding:6px;">Tipologia</th><th style="border:1px solid #ccc;padding:6px;">Motivo</th><th style="border:1px solid #ccc;padding:6px;">Urgencia (dias)</th><th style="border:1px solid #ccc;padding:6px;">Impacto est.</th><th style="border:1px solid #ccc;padding:6px;">Prioridad</th>' +
    '</tr></thead><tbody>' + rows + '</tbody></table>' +
    '<p style="margin-top:16px;">Estas son tus alertas prioritarias de hoy. Cada contacto realizado se registra en Pulse.</p>' +
    '<hr style="border:none;border-top:1px solid #ddd;margin:16px 0;"><p style="font-size:11px;color:#888;">La actividad de competencia no se observa directamente; se infiere del gap entre potencial declarado y compras Inibsa.</p></div>';
  out.push({ json: { canal: ch, canal_label: CHANNEL_LABEL[ch] || ch, count: list.length, shown: top.length, pipeline_canal_eur: Math.round(totalImpact), subject: 'Pulse - ' + top.length + ' alertas prioritarias (' + (CHANNEL_LABEL[ch] || ch) + ')', html } });
}
return out;

const stats = $('Consultar stats (GET /stats)').first().json || {};
const recalc = $('Recalcular senales (POST /run-recalc)').first().json || {};
const alertsResp = $('Recoger alertas (GET /alerts)').first().json || {};
const items = Array.isArray(alertsResp) ? alertsResp : (alertsResp.items || []);

const fmtInt = (n) => Math.round(Number(n) || 0).toLocaleString('de-DE');
const TR = { loyal: 'leal', promiscuous: 'promiscuo', at_risk: 'en riesgo de fuga', marginal: 'marginal' };

const byChannel = {};
for (const a of items) { const c = a.canal_recomendado || 'sin_canal'; byChannel[c] = (byChannel[c] || 0) + 1; }
const channelRows = Object.entries(byChannel).map(([c, n]) => '<tr><td style="border:1px solid #ccc;padding:6px;">' + c + '</td><td style="border:1px solid #ccc;padding:6px;text-align:right;">' + n + '</td></tr>').join('');
const tipoRows = Object.entries(stats.by_tipologia || {}).map(([k, v]) => '<tr><td style="border:1px solid #ccc;padding:6px;">' + (TR[k] || k) + '</td><td style="border:1px solid #ccc;padding:6px;text-align:right;">' + v + '</td></tr>').join('');

const html = '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;color:#222;">' +
  '<h2 style="color:#1a4d8f;">Pulse &middot; Resumen diario de activacion</h2>' +
  '<p>Recalculo ejecutado correctamente en ' + (recalc.elapsed_seconds != null ? recalc.elapsed_seconds : 'n/d') + 's. <strong>' + fmtInt(recalc.alerts_generated) + '</strong> alertas generadas.</p>' +
  '<ul><li>Alertas activas: <strong>' + fmtInt(stats.active_alerts) + '</strong></li><li>Alertas urgentes: <strong>' + fmtInt(stats.urgent_alerts) + '</strong></li><li>Pipeline estimado total: <strong>' + fmtInt(stats.pipeline_eur) + ' &euro;</strong></li></ul>' +
  '<h3>Alertas por canal (entre las top ' + items.length + ' recogidas)</h3><table style="border-collapse:collapse;font-size:13px;"><thead><tr style="background:#1a4d8f;color:#fff;"><th style="border:1px solid #ccc;padding:6px;">Canal</th><th style="border:1px solid #ccc;padding:6px;">N</th></tr></thead><tbody>' + channelRows + '</tbody></table>' +
  '<h3>Alertas por tipologia (global)</h3><table style="border-collapse:collapse;font-size:13px;"><thead><tr style="background:#1a4d8f;color:#fff;"><th style="border:1px solid #ccc;padding:6px;">Tipologia</th><th style="border:1px solid #ccc;padding:6px;">N</th></tr></thead><tbody>' + tipoRows + '</tbody></table>' +
  '<p style="margin-top:16px;">Los digests por canal ya se han enviado a cada equipo. Cada contacto realizado se registra en Pulse.</p>' +
  '<hr style="border:none;border-top:1px solid #ddd;margin:16px 0;"><p style="font-size:11px;color:#888;">La actividad de competencia no se observa directamente; se infiere del gap entre potencial declarado y compras Inibsa.</p></div>';

return [{ json: { html, subject: 'Pulse - Resumen diario (' + fmtInt(stats.active_alerts) + ' alertas activas)', alerts_generated: recalc.alerts_generated, active_alerts: stats.active_alerts, pipeline_eur: stats.pipeline_eur } }];
